import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.TimeUnit;

/**
 * Service class for file management operations.
 * Provides functionality to search files using pattern matching.
 */
public class FileService {

    // Maximum number of results to return
    private static final int MAX_RESULTS = 10;
    // Timeout for command execution in seconds
    private static final long COMMAND_TIMEOUT_SECONDS = 30;

    /**
     * Searches for files matching the given pattern in the specified directory.
     * Uses bash find command with -name parameter for pattern matching.
     *
     * @param searchDir   the directory path to search in
     * @param filePattern the file pattern to match (supports wildcards like *.txt)
     * @return a string containing found file paths (one per line), or an error message
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        // Validate input parameters
        if (searchDir == null || searchDir.trim().isEmpty()) {
            return "Error: Search directory cannot be null or empty";
        }
        if (filePattern == null || filePattern.trim().isEmpty()) {
            return "Error: File pattern cannot be null or empty";
        }

        // Normalize and validate the search directory path
        Path normalizedPath;
        try {
            normalizedPath = Paths.get(searchDir).normalize().toAbsolutePath();
            // Ensure the path exists and is a directory
            if (!normalizedPath.toFile().exists()) {
                return "Error: Search directory does not exist: " + searchDir;
            }
            if (!normalizedPath.toFile().isDirectory()) {
                return "Error: Search path is not a directory: " + searchDir;
            }
        } catch (Exception e) {
            return "Error: Invalid search directory path: " + e.getMessage();
        }

        // Escape the file pattern to prevent command injection
        // Wrap the pattern in single quotes and escape any single quotes within it
        String escapedPattern = escapeShellArgument(filePattern);

        // Build the find command using bash -c
        // Command: find <searchDir> -type f -name <pattern> -maxdepth 10 | head -n 10
        String findCommand = String.format(
            "find %s -type f -name %s -maxdepth 10 2>/dev/null | head -n %d",
            escapeShellArgument(normalizedPath.toString()),
            escapedPattern,
            MAX_RESULTS
        );

        // Execute the command using bash -c
        ProcessBuilder processBuilder = new ProcessBuilder("bash", "-c", findCommand);

        // Set working directory to a safe location
        processBuilder.directory(new java.io.File(System.getProperty("user.home")));

        Process process = null;
        try {
            process = processBuilder.start();

            // Read command output
            List<String> outputLines = readProcessOutput(process.getInputStream());

            // Wait for process completion with timeout
            boolean finished = process.waitFor(COMMAND_TIMEOUT_SECONDS, TimeUnit.SECONDS);
            if (!finished) {
                process.destroyForcibly();
                return "Error: Command execution timed out";
            }

            // Check exit code
            int exitCode = process.exitValue();
            if (exitCode != 0 && exitCode != 1) { // exit code 1 means no matches found, which is OK
                // Read error stream for more details
                List<String> errorLines = readProcessOutput(process.getErrorStream());
                String errorMsg = String.join("; ", errorLines);
                return "Error: Command failed with exit code " + exitCode + 
                       (errorMsg.isEmpty() ? "" : ": " + errorMsg);
            }

            // Return results or appropriate message
            if (outputLines.isEmpty()) {
                return "No files found matching pattern: " + filePattern;
            }

            return String.join("\n", outputLines);

        } catch (IOException e) {
            return "Error: Failed to execute command: " + e.getMessage();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return "Error: Command execution was interrupted";
        } finally {
            if (process != null && process.isAlive()) {
                process.destroyForcibly();
            }
        }
    }

    /**
     * Escapes a string argument for safe use in shell commands.
     * Wraps the argument in single quotes and handles embedded single quotes.
     *
     * @param arg the argument to escape
     * @return the escaped argument
     */
    private String escapeShellArgument(String arg) {
        if (arg == null) {
            return "''";
        }
        // Replace each single quote with '\'' (end quote, escaped quote, start quote)
        // Then wrap the whole thing in single quotes
        String escaped = arg.replace("'", "'\\''");
        return "'" + escaped + "'";
    }

    /**
     * Reads all lines from an input stream.
     *
     * @param inputStream the input stream to read from
     * @return list of lines read from the stream
     * @throws IOException if an I/O error occurs
     */
    private List<String> readProcessOutput(InputStream inputStream) throws IOException {
        List<String> lines = new ArrayList<>();
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
            String line;
            while ((line = reader.readLine()) != null) {
                if (!line.trim().isEmpty()) {
                    lines.add(line);
                }
            }
        }
        return lines;
    }
}

